public static void TestChaCha8(ж<testing.T> Ꮡt) {
    var p = NewChaCha8(chacha8seed);
    foreach (var (i, x) in chacha8output) {
        {
            var u = p.Uint64(); if (u != x) {
                Ꮡt.Errorf("ChaCha8 #%d = %#x, want %#x"u8, i, u, x);
            }
        }
    }
    p.Seed(chacha8seed);
    foreach (var (i, x) in chacha8output) {
        {
            var u = p.Uint64(); if (u != x) {
                Ꮡt.Errorf("ChaCha8 #%d = %#x, want %#x"u8, i, u, x);
            }
        }
    }
}

public static void TestChaCha8Read(ж<testing.T> Ꮡt) {
    var p = NewChaCha8(chacha8seed);
    var h = sha256.New();
    var buf = new slice<byte>(chacha8outlen);
    {
        var (nn, err) = p.Read(buf); if (err != default!){
            Ꮡt.Fatal(err);
        } else 
        if (nn != len(buf)) {
            Ꮡt.Errorf("Read short: got %d, expected %d"u8, nn, len(buf));
        }
    }
    h.Write(buf);
    {
        var got = h.Sum(default!); if (!bytes.Equal(got, chacha8hash)) {
            Ꮡt.Errorf("transcript incorrect: got %x, want %x"u8, got, chacha8hash);
        }
    }
    p.Seed(chacha8seed);
    h.Reset();
    buf = new slice<byte>(chacha8outlen);
    {
        var (_, err) = io.ReadFull(iotest.OneByteReader(new rand.ChaCha8жReader(p)), buf); if (err != default!) {
            Ꮡt.Errorf("one byte reads: %v"u8, err);
        }
    }
    h.Write(buf);
    {
        var got = h.Sum(default!); if (!bytes.Equal(got, chacha8hash)) {
            Ꮡt.Errorf("transcript incorrect (one byte reads): got %x, want %x"u8, got, chacha8hash);
        }
    }
    p.Seed(chacha8seed);
    h.Reset();
    {
        var (nΔ1, err) = p.Read(new slice<byte>(0)); if (err != default!){
            Ꮡt.Errorf("zero length read: %v"u8, err);
        } else 
        if (nΔ1 != 0) {
            Ꮡt.Errorf("Read zero length: got %d, expected %d"u8, nΔ1, 0);
        }
    }
    nint n = default!;
    while (n < chacha8outlen) {
        if (IntN(2) == 0) {
            var (@out, err) = p.MarshalBinary();
            if (err != default!) {
                Ꮡt.Fatal(err);
            }
            if (IntN(2) == 0) {
                p = NewChaCha8(new byte[]{}.array(32));
            }
            {
                var errΔ1 = p.UnmarshalBinary(@out); if (errΔ1 != default!) {
                    Ꮡt.Fatal(errΔ1);
                }
            }
        }
        var bufΔ1 = new slice<byte>(IntN(100));
        if (n + len(bufΔ1) > chacha8outlen) {
            bufΔ1 = bufΔ1[..(int)(chacha8outlen - n)];
        }
        n += len(bufΔ1);
        Ꮡt.Logf("reading %d bytes"u8, len(bufΔ1));
        {
            var (nn, err) = p.Read(bufΔ1); if (err != default!){
                Ꮡt.Fatal(err);
            } else 
            if (nn != len(bufΔ1)) {
                Ꮡt.Errorf("Read short: got %d, expected %d"u8, nn, len(bufΔ1));
            }
        }
        h.Write(bufΔ1);
    }
    {
        var got = h.Sum(default!); if (!bytes.Equal(got, chacha8hash)) {
            Ꮡt.Errorf("transcript incorrect: got %x, want %x"u8, got, chacha8hash);
        }
    }
}

public static void TestChaCha8Marshal(ж<testing.T> Ꮡt) {
    var p = NewChaCha8(chacha8seed);
    foreach (var (i, x) in chacha8output) {
        var (enc, err) = p.MarshalBinary();
        if (err != default!) {
            Ꮡt.Fatalf("#%d: MarshalBinary: %v"u8, i, err);
        }
        if (((sstring)enc) != chacha8marshal[i]) {
            Ꮡt.Errorf("#%d: MarshalBinary=%q, want %q"u8, i, enc, chacha8marshal[i]);
        }
        p.Value = new ChaCha8(nil);
        {
            var errΔ1 = p.UnmarshalBinary(enc); if (errΔ1 != default!) {
                Ꮡt.Fatalf("#%d: UnmarshalBinary: %v"u8, i, errΔ1);
            }
        }
        {
            var u = p.Uint64(); if (u != x) {
                Ꮡt.Errorf("ChaCha8 #%d = %#x, want %#x"u8, i, u, x);
            }
        }
    }
}

public static void TestChaCha8MarshalRead(ж<testing.T> Ꮡt) {
    var p = NewChaCha8(chacha8seed);
    foreach (var i in range(50)) {
        var (enc, err) = p.MarshalBinary();
        if (err != default!) {
            Ꮡt.Fatalf("#%d: MarshalBinary: %v"u8, i, err);
        }
        if (((sstring)enc) != chacha8marshalread[i]) {
            Ꮡt.Errorf("#%d: MarshalBinary=%q, want %q"u8, i, enc, chacha8marshalread[i]);
        }
        p.Value = new ChaCha8(nil);
        {
            var errΔ1 = p.UnmarshalBinary(enc); if (errΔ1 != default!) {
                Ꮡt.Fatalf("#%d: UnmarshalBinary: %v"u8, i, errΔ1);
            }
        }
        p.Read(new slice<byte>(1));
    }
}

public static void BenchmarkChaCha8(ж<testing.B> Ꮡb) {
    ref var b = ref Ꮡb.Value;

    var p = NewChaCha8(new byte[]{1, 2, 3, 4, 5}.array(32));
    uint64 t = default!;
    for (nint n = b.N; n > 0; n--) {
        t += p.Uint64();
    }
    Sink = t;
}

public static void BenchmarkChaCha8Read(ж<testing.B> Ꮡb) {
    ref var b = ref Ꮡb.Value;

    var p = NewChaCha8(new byte[]{1, 2, 3, 4, 5}.array(32));
    var buf = new slice<byte>(32);
    b.SetBytes(32);
    uint8 t = default!;
    for (nint n = b.N; n > 0; n--) {
        p.Read(buf);
        t += buf[0];
    }
    Sink = (uint64)t;
}

